import Cluster from "@/components/primitives/Cluster";
import Link from "@/components/primitives/Link";
import press from "@/content/projects/hivemind/press";

// Surface only real external artifacts — github / demo / paper kinds whose
// href is not a placeholder. press.ts currently lists those as `(pending)`
// with href "#"; the site-wide website + product-login already render in
// the project shell metadata, so they are excluded here to avoid duplication.
const ARTIFACT_KINDS = new Set(["github", "demo", "press"]);

function isReal(href: string): boolean {
  return href.length > 1 && href !== "#" && !href.startsWith("mailto:");
}

export default function Links() {
  const items = press.filter(
    (a) => ARTIFACT_KINDS.has(a.kind) && isReal(a.href),
  );

  if (items.length === 0) return null;

  return (
    <Cluster as="nav" gap={4} aria-label="Project artifacts">
      {items.map((item) => (
        <Link key={item.href} href={item.href} external>
          {item.label}
        </Link>
      ))}
    </Cluster>
  );
}

import type { ProjectMetadata } from "@/lib/projects/types";

export const metadata: ProjectMetadata = {
  slug: "purposeless-efficiency",
  code: "PRP",
  title: "Purposeless Efficiency",
  tagline: "Book I — efficiency severed from purpose.",
  status: "in-progress",
  framing:
    "Purposeless Efficiency is a book-length argument that the modern condition is shaped by optimization without an examined end. It traces the divorce between means and meaning across institutions, technology, and personal life. The book proposes a method for re-coupling them.",
  seedQuestion:
    "What is the central argument of Purposeless Efficiency?",
};

export default metadata;

// TODO(michael): replace with the real preface
const preface = [
  "This book began as a refusal. The refusal was simple: to keep producing inside systems whose only consistent output was the perpetuation of themselves. The refusal was also, more uncomfortably, a confession. I was good at producing inside those systems. The confession is what made the book necessary.",
  "Purposeless Efficiency is the first of five volumes. It examines what efficiency means once it has been severed from any external purpose — once the metric is the meaning. The remaining volumes will treat what comes after the severance: the institutions that survive it, the ones that do not, and what an honest economic order might look like once we admit the mistake.",
  "Reader, I assume you have already noticed the symptoms. The book is for the reader who has stopped pretending the symptoms are accidental.",
];
export default preface;

// TODO(michael): rewrite each pillar body in your voice
export type Pillar = {
  num: "I" | "II" | "III" | "IV" | "V";
  title: string;
  seed: string;       // single-line collapsed quote
  body: string;       // expanded paragraph(s)
};

const pillars: Pillar[] = [
  { num: "I",  title: "Corporatism",
    seed: "What it has done to work, and what it calls 'ambition.'",
    body: "Corporatism is the management of human attention by institutions whose primary product is no longer goods or services but the legitimation of their own continued existence. Ambition, under corporatism, is the willingness to mistake the institution's survival for one's own." },
  { num: "II", title: "Gamification",
    seed: "The industry of scoring, ranking, grinding; and its psychological residue.",
    body: "When every workflow becomes a leaderboard, the leaderboard becomes the workflow. The optimization target eats the optimized object. Gamification is not a UX choice; it is a worldview." },
  { num: "III", title: "Incumbency",
    seed: "Why the machine does not die when it should.",
    body: "Incumbents persist not because they are right but because they are wired into the substrate of decision-making. Their replacement requires not better arguments but a different substrate." },
  { num: "IV", title: "Complacency",
    seed: "The citizen's withdrawal, and the elite's.",
    body: "Complacency is the rational response to a system whose levers have been disconnected from outcomes. The cost of paying attention exceeds the expected return on attention. The citizen withdraws; so, eventually, does the elite." },
  { num: "V",  title: "Economic Revolution",
    seed: "What comes next, and how we avoid the failure modes of the last one.",
    body: "Revolution requires a coherent alternative, not merely a critique. The alternative must be operable by humans of ordinary virtue, or it will be captured by humans of extraordinary ambition." },
];
export default pillars;

